<template>
  <div style="width: 40%; margin-left: 200px">
    <div style="margin-bottom: 50px; margin-left: 280px" >新增出版社</div>
    <el-form :model="ruleForm" :rules="rules" ref="ruleForm" label-width="200px">
      <el-form-item label="楼层" prop="floor">
        <el-input-number v-model="ruleForm.floor"  :min="1" :max="10" ></el-input-number>
      </el-form-item>
      <el-form-item label="区域" prop="area">
        <el-input v-model="ruleForm.area" placeholder="请输入区域"></el-input>
      </el-form-item>
      <el-form-item label="负责人" prop="admin">
        <el-cascader
            :props="{value: 'id', label: 'id'}"
            v-model="ruleForm.admins"
            :options="admins"
            @change="handleChange"></el-cascader>
      </el-form-item>
    </el-form>
    <div style="margin-left: 250px; margin-top: 40px">
      <el-button type="primary" @click="save">提交</el-button>
      <el-button style="background-color: #f3d19e; color: white" @click="change">返回</el-button>
      <!--            <el-button type="danger ">取消</el-button>-->
    </div>
  </div>
</template>

<script>
import request from "@/utils/request";
//导入请求
export default {
  name: "AddPublish",
  data(){

    // 自定义的校验
    return {
      ruleForm: {

      },
      rules: {},
      admins:[]
    }

  },
  created() {
    request.get('/admin/list').then(res => {
      this.admins = res.data;
    })

  },
  methods: {
    save() {
      //this.$refs与ref关联的，可以获取dom元素和子组件实例，配合validate对整个表单进行校验，valid每个必填表单项都提交为true，否则为false，规范化的操作
      this.$refs['ruleForm'].validate((valid) => {
        if(valid){
          request.post('/location/save',this.ruleForm).then(res =>{
            if(res.code === '200'){
              this.$notify.success('添加成功')
              // 重置表单
              this.$refs['ruleForm'].resetFields();
              this.$router.push('locationList');
            }else{
              this.$notify.error(res.msg)
            }
          })
        }
      })

    },
    change(){
      this.$router.push('locationList')
    },
    handleChange(){

    }
  }
}
</script>

